class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.container.appendChild(this.canvas);
        this.resize();
        window.addEventListener('resize', () => this.resize());
    }
    resize() {
        this.canvas.width = this.container.clientWidth;
        this.canvas.height = this.container.clientHeight;
    }
    getSteps(inputs) {
        const steps = [];
        steps.push({
            title: 'Step 1: Dataset',
            description: `A random dataset of ${inputs.datasetSize} points is generated in the unit square. The query point is (${inputs.pointX.toFixed(2)}, ${inputs.pointY.toFixed(2)}).`
        });
        steps.push({
            title: 'Step 2: Distances',
            description: `Distances from the query point to each dataset point are computed. The ${inputs.k} nearest neighbors are highlighted.`
        });
        steps.push({
            title: 'Step 3: Classification',
            description: `The majority class among the ${inputs.k} nearest neighbors determines the class of the query point.`
        });
        return steps;
    }
    render(inputs, stepIndex) {
        const ctx = this.ctx;
        const w = this.canvas.width;
        const h = this.canvas.height;
        ctx.clearRect(0, 0, w, h);
        // ---- generate random dataset ----
        const points = [];
        for (let i = 0; i < inputs.datasetSize; i++) {
            const x = Math.random();
            const y = Math.random();
            const cls = Math.random() < 0.5 ? 'A' : 'B';
            points.push({ x, y, cls });
        }
        // ---- draw dataset points ----
        points.forEach(p => {
            ctx.fillStyle = p.cls === 'A' ? '#3b82f6' : '#ef4444'; // blue for A, red for B
            ctx.beginPath();
            ctx.arc(p.x * w, p.y * h, 5, 0, 2 * Math.PI);
            ctx.fill();
        });
        // ---- draw query point ----
        const qx = inputs.pointX;
        const qy = inputs.pointY;
        ctx.fillStyle = '#fbbf24'; // amber
        ctx.beginPath();
        ctx.arc(qx * w, qy * h, 7, 0, 2 * Math.PI);
        ctx.fill();
        if (stepIndex >= 1) {
            // compute distances and find nearest neighbors
            const dists = points.map(p => ({ p, d: Math.hypot(p.x - qx, p.y - qy) }));
            dists.sort((a, b) => a.d - b.d);
            const nearest = dists.slice(0, inputs.k);
            // draw lines to nearest neighbors
            ctx.strokeStyle = '#10b981'; // emerald
            ctx.lineWidth = 2;
            nearest.forEach(n => {
                ctx.beginPath();
                ctx.moveTo(qx * w, qy * h);
                ctx.lineTo(n.p.x * w, n.p.y * h);
                ctx.stroke();
            });
            // highlight nearest points
            nearest.forEach(n => {
                ctx.fillStyle = '#10b981';
                ctx.beginPath();
                ctx.arc(n.p.x * w, n.p.y * h, 8, 0, 2 * Math.PI);
                ctx.fill();
            });
        }
        if (stepIndex >= 2) {
            // classification result
            const dists = points.map(p => ({ p, d: Math.hypot(p.x - qx, p.y - qy) }));
            dists.sort((a, b) => a.d - b.d);
            const nearest = dists.slice(0, inputs.k);
            const countA = nearest.filter(n => n.p.cls === 'A').length;
            const countB = nearest.filter(n => n.p.cls === 'B').length;
            const cls = countA > countB ? 'A' : 'B';
            ctx.fillStyle = 'white';
            ctx.font = '20px sans-serif';
            ctx.fillText(`Classified as ${cls}`, 10, h - 20);
        }
    }
}
